     1→//! R-style formula parsing and design matrix specification
     2→//!
     3→//! This crate provides compile-time and run-time parsing of statistical formulas
     4→//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
     5→//! design matrix generators.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use pest::iterators::Pair;
    11→use pest::Parser;
    12→
    13→// Allow missing docs for generated code
    14→#[allow(missing_docs)]
    15→mod parser_generated {
    16→    use pest_derive::Parser;
    17→
    18→    /// Internal parser implementation for formula grammar
    19→    #[derive(Parser)]
    20→    #[grammar = "formula.pest"]
    21→    pub struct FormulaParser;
    22→}
    23→
    24→use parser_generated::{FormulaParser, Rule};
    25→
    26→/// Formula parsing errors
    27→#[derive(thiserror::Error, Debug)]
    28→pub enum FormulaError {
    29→    /// Parse error from pest
    30→    #[error("Formula parse error: {0}")]
    31→    Parse(String),
    32→    /// Semantic validation error
    33→    #[error("Formula validation error: {0}")]
    34→    Validation(String),
    35→}
    36→
    37→/// Abstract syntax tree representing a parsed statistical formula
    38→#[derive(Debug, Clone, PartialEq)]
    39→pub struct ModelSpec {
    40→    /// The response variable(s)
    41→    pub response: Vec<String>,
    42→    /// The predictor terms
    43→    pub terms: Vec<Term>,
    44→}
    45→
    46→/// A term in a statistical formula
    47→#[derive(Debug, Clone, PartialEq)]
    48→pub enum Term {
    49→    /// Intercept term
    50→    Intercept,
    51→    /// Variable name
    52→    Variable(String),
    53→    /// Interaction between terms
    54→    Interaction(Vec<Term>),
    55→    /// Function call (e.g., I(x^2), poly(x, 2))
    56→    Function {
    57→        /// Function name
    58→        name: String,
    59→        /// Function arguments
    60→        args: Vec<String>,
    61→    },
    62→}
    63→
    64→impl ModelSpec {
    65→    /// Create a simple formula with intercept
    66→    pub fn intercept_only(response: &str) -> Self {
    67→        Self {
    68→            response: vec![response.to_string()],
    69→            terms: vec![Term::Intercept],
    70→        }
    71→    }
    72→
    73→    /// Add a variable term
    74→    pub fn add_variable(&mut self, var: &str) {
    75→        self.terms.push(Term::Variable(var.to_string()));
    76→    }
    77→}
    78→
    79→/// Parse a formula string into a ModelSpec  
    80→pub fn parse_formula(formula: &str) -> Result<ModelSpec, FormulaError> {
    81→    let mut pairs = FormulaParser::parse(Rule::formula, formula)
    82→        .map_err(|e| FormulaError::Parse(e.to_string()))?;
    83→
    84→    let formula_pair = pairs.next().unwrap();
    85→    let mut response = Vec::new();
    86→    let mut terms = Vec::new();
    87→
    88→    for pair in formula_pair.into_inner() {
    89→        match pair.as_rule() {
    90→            Rule::response => {
    91→                let var_pair = pair.into_inner().next().unwrap();
    92→                response.push(var_pair.as_str().trim().to_string());
    93→            }
    94→            Rule::terms => {
    95→                for term_pair in pair.into_inner() {
    96→                    if let Ok(term) = parse_term(term_pair) {
    97→                        terms.push(term);
    98→                    }
    99→                }
   100→            }
   101→            Rule::EOI => {}
   102→            _ => {}
   103→        }
   104→    }
   105→
   106→    Ok(ModelSpec { response, terms })
   107→}
   108→
   109→fn parse_term(pair: Pair<Rule>) -> Result<Term, FormulaError> {
   110→    match pair.as_rule() {
   111→        Rule::term => {
   112→            let inner = pair.into_inner().next().unwrap();
   113→            parse_term(inner)
   114→        }
   115→        Rule::variable => Ok(Term::Variable(pair.as_str().trim().to_string())),
   116→        Rule::interaction => {
   117→            let mut variables = Vec::new();
   118→            for var_pair in pair.into_inner() {
   119→                if var_pair.as_rule() == Rule::variable {
   120→                    variables.push(Term::Variable(var_pair.as_str().trim().to_string()));
   121→                }
   122→            }
   123→            Ok(Term::Interaction(variables))
   124→        }
   125→        _ => {
   126→            if pair.as_str() == "1" {
   127→                Ok(Term::Intercept)
   128→            } else {
   129→                Err(FormulaError::Parse(format!(
   130→                    "Unknown term: {}",
   131→                    pair.as_str()
   132→                )))
   133→            }
   134→        }
   135→    }
   136→}
   137→
   138→#[cfg(test)]
   139→mod tests {
   140→    use super::*;
   141→
   142→    #[test]
   143→    fn test_parse_simple_formula() {
   144→        let result = parse_formula("y ~ x").unwrap();
   145→        assert_eq!(result.response, vec!["y"]);
   146→        assert_eq!(result.terms.len(), 1);
   147→        assert_eq!(result.terms[0], Term::Variable("x".to_string()));
   148→    }
   149→
   150→    #[test]
   151→    fn test_parse_multiple_variables() {
   152→        let result = parse_formula("mpg ~ wt + hp").unwrap();
   153→        assert_eq!(result.response, vec!["mpg"]);
   154→        assert_eq!(result.terms.len(), 2);
   155→        assert_eq!(result.terms[0], Term::Variable("wt".to_string()));
   156→        assert_eq!(result.terms[1], Term::Variable("hp".to_string()));
   157→    }
   158→
   159→    #[test]
   160→    fn test_parse_interaction() {
   161→        let result = parse_formula("y ~ x1 * x2").unwrap();
   162→        assert_eq!(result.response, vec!["y"]);
   163→        assert_eq!(result.terms.len(), 1);
   164→
   165→        if let Term::Interaction(vars) = &result.terms[0] {
   166→            assert_eq!(vars.len(), 2);
   167→            assert_eq!(vars[0], Term::Variable("x1".to_string()));
   168→            assert_eq!(vars[1], Term::Variable("x2".to_string()));
   169→        } else {
   170→            panic!("Expected interaction term");
   171→        }
   172→    }
   173→
   174→    #[test]
   175→    fn test_parse_complex_formula() {
   176→        let result = parse_formula("mpg ~ wt + hp * cyl").unwrap();
   177→        assert_eq!(result.response, vec!["mpg"]);
   178→        assert_eq!(result.terms.len(), 2);
   179→        assert_eq!(result.terms[0], Term::Variable("wt".to_string()));
   180→
   181→        if let Term::Interaction(vars) = &result.terms[1] {
   182→            assert_eq!(vars.len(), 2);
   183→            assert_eq!(vars[0], Term::Variable("hp".to_string()));
   184→            assert_eq!(vars[1], Term::Variable("cyl".to_string()));
   185→        } else {
   186→            panic!("Expected interaction term");
   187→        }
   188→    }
   189→
   190→    #[test]
   191→    fn test_invalid_formula() {
   192→        let result = parse_formula("invalid formula without ~");
   193→        assert!(result.is_err());
   194→    }
   195→}
