use ndarray::ShapeBuilder;

pub fn build(self) -> Array2<f64> {
    if self.columns.is_empty() {
        return Array2::zeros((self.n_rows, 0));
    }

    let n_cols = self.columns.len();
    let flat_data: Vec<f64> = self.columns.into_iter().flatten().collect();

    // Build a column-major array directly from the flattened column data.
    Array2::from_shape_vec((self.n_rows, n_cols).f(), flat_data)
        .expect("Shape and data length should match")
}
